operation.expression:
if(
util:getOrganizationId() eq '1PvEqToGQYmhyhRzQkHEOw'
) then 'IDMC Dev'
else if(
util:getOrganizationId() eq '61GyMvRzEfcif87DSGOisg'
) then 'IDMC QA'
else if(
util:getOrganizationId() eq '4Dn2SaPlyijdm4KqNTO4W2'
) then 'IDMC Prod'
else util:getOrganizationId()

if(
util:resolveURN('OrgName') eq 'Dev'
) then '//dcusfs01.quakerone.com/Informatica/Dev'
else if(
util:resolveURN('OrgName') eq 'Test'
) then '//dcusfs01.quakerone.com/Informatica/Acp'
else if(
util:resolveURN('OrgName') eq 'Prod'
) then '//dcusfs01.quakerone.com/Informatica/Prd'
else ''

let $filePath := $temp.tmp_FilesMissing_FilePath let $fileName := $temp.tmp_FilesMissing_Filename
let $uri := fn:concat('file:///', $filePath, '/', $fileName)
let $csvContent := unparsed-text($uri)
let $lines := tokenize($csvContent, '\r?\n')
return
for $line at $pos in $lines where $pos > 1 and normalize-space($line) != "" and count(tokenize($line, '\|')) > 1
let $fields := tokenize($line, '\|')
return <JDEData> <F0101_ABAN8>{ $fields[1] }</F0101_ABAN8> <F0111_WWMLNM>{ $fields[2] }</F0111_WWMLNM> <F0101_ABAT1>{ $fields[3] }</F0101_ABAT1> <REMARK_TEXT>{ $fields[4] }</REMARK_TEXT> <F0101_ABTAX>{ $fields[5] }</F0101_ABTAX> <F0116_ALADD1>{ $fields[6] }</F0116_ALADD1> <F0116_ALADD2>{ $fields[7] }</F0116_ALADD2> <F0116_ALADD3>{ $fields[8] }</F0116_ALADD3> <F0116_ALADD4>{ $fields[9] }</F0116_ALADD4> <F0116_ALCTY1>{ $fields[10] }</F0116_ALCTY1> <F0116_ALADDZ>{ $fields[11] }</F0116_ALADDZ> <F0116_ALADDS>{ $fields[12] }</F0116_ALADDS> <STATE_NAME>{ $fields[13] }</STATE_NAME> <F0116_ALCTR>{ $fields[14] }</F0116_ALCTR> </JDEData>

let $dt := fn:string(fn:current-dateTime())

return
fn:concat('_', fn:replace(
  fn:substring($dt, 1, 19),
  '[-:T]',
  ''
))

let $dt := current-dateTime()
let $prevHour := $dt - xs:dayTimeDuration("PT1H")

(: YYYYMMDD_HH0000 :)
let $formatted :=
  format-dateTime($prevHour, "[Y0001][M01][D01]_[H01]0000")

(: milliseconds :)
let $millis :=
  substring(
    format-dateTime($prevHour, "[f]"),
    1,
    3
  )

return 
fn:concat(
  'JDE_CustomerSupplier_Processed_records_',
  $formatted,
  $millis,
  '.csv'
)

parameter.expression:
fn:concat(
$temp.tmp_OrgName, ': ', 
'IDMC Process: ', 
$temp.tmp_ProcessName, 
' - Process Sucessfully pushed Data to GTM'
)

fn:concat(
$temp.tmp_OrgName, ': ', 
