operation.expression:
let $dt := current-dateTime()

let $date := xs:date($dt)
let $year := year-from-date($date)
let $startOfYear := xs:date(concat($year, '-01-01'))
let $dayOfYear := days-from-duration($date - $startOfYear) + 1
let $julian := (($year - 1900) * 1000) + $dayOfYear

(: HHmmss :)
let $time :=
  format-dateTime($dt, "[H01][m01][s01]")

(: milliseconds :)
let $millis :=
  substring(
    format-dateTime($dt, "[f]"),
    1,
    3
  )

return
fn:concat($julian, $time, $millis, $temp.tmp_F0101_ABAN8)
